  ?event wdt:P31 wd:Q1363275 ;
         wdt:P1923 wd:Q334634 ;
         wdt:P1923 wd:Q650840 ;
         wdt:P585 ?date ;
         wdt:P2471 ?games .

  BIND(YEAR(?date) AS ?year)
